import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import datasets, transforms, models
import urllib.request
import os

# Function to download model checkpoint from a URL
def download_checkpoint(url, filename):
    if not os.path.exists(filename):
        urllib.request.urlretrieve(url, filename)

# Load model checkpoint
def load_model_from_url(url):
    checkpoint_filename = 'model_checkpoint.pth'
    download_checkpoint(url, checkpoint_filename)
    model = torch.load(checkpoint_filename)
    return model

# Fine-tune model on custom dataset
def fine_tune_model(model, train_loader, num_epochs=5, learning_rate=0.001):
    # Assuming model is a torchvision model with a classifier attribute
    model.classifier = nn.Sequential(
        nn.Linear(model.classifier[0].in_features, 256),
        nn.ReLU(),
        nn.Dropout(0.4),
        nn.Linear(256, len(train_loader.dataset.classes))
    )
    
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    model.train()
    for epoch in range(num_epochs):
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
        print(f'Epoch {epoch+1}/{num_epochs}, Loss: {loss.item()}')
    return model

# Example usage
def main():
    # URL of the pretrained model checkpoint
    model_url = 'https://download.pytorch.org/models/resnet18-5c106cde.pth'
    
    # Load the model
    model = load_model_from_url(model_url)
    
    # Prepare custom dataset
    transform = transforms.Compose([transforms.Resize((224, 224)), transforms.ToTensor()])
    train_dataset = datasets.FakeData(transform=transform)
    train_loader = torch.utils.data.DataLoader(train_dataset, batch_size=32, shuffle=True)
    
    # Fine-tune the model
    fine_tuned_model = fine_tune_model(model, train_loader)

if __name__ == "__main__":
    main()